import { html, customElement, property, state, css, when } from '@umbraco-cms/backoffice/external/lit';
import type { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { UUIInputEvent } from '@umbraco-ui/uui-input';
import { FORMS_FORM_WORKSPACE_CONTEXT } from '../../section/forms/workspace/form-workspace.context-token';
import { Field, MappedDocumentTypeModel, MappedDocumentTypePropertyModel, PickerItem, PickerService } from '@umbraco-forms/generated';
import { UUISelectEvent } from '@umbraco-ui/uui';
import { tryExecuteAndNotify } from '@umbraco-cms/backoffice/resources';

const elementName = "forms-document-mapper-property-editor";

export type DocumentMapping = { doctype: string, nameField?: string, nameStaticValue?: string, properties: Array<MappedDocumentTypePropertyModel> }

@customElement(elementName)
export class FormsDocumentMapperPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;

  #value: string = "";

  @property({ type: String })
  get value() { return this.#value; }
  set value(value: string) {
    let oldVal = this.#value;
    this.#value = value;
    this.requestUpdate('value', oldVal);

    this.#initializeMapping(value);
  }

  #mapping: DocumentMapping = this.#createScaffold();

  #docTypes: Array<PickerItem> = [];

  #fieldSelectOptions: Array<Option> = [];

  constructor() {
    super();

		this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
			this.#workspaceContext = instance;
      this.#initializeDocTypes();
      this.#initializeFieldSelectOptions();
		});
  }

  #createScaffold() {
    return { doctype: "", nameField: "", nameStaticValue: "", properties: []};
  }

  #initializeMapping(value?: string) {
    if (value && value.length > 0) {
      this.#mapping = JSON.parse(value);
      this.#cleanMapping();
    }
  }

  #cleanMapping() {
    // Remove the tracking values added previously in angularjs.
    for (let index = 0; index < this.#mapping.properties.length; index++) {
      const property = this.#mapping.properties[index];
      delete property["$$hashKey"];
    }
  }

  async #initializeDocTypes() {
		const { data } = await tryExecuteAndNotify(
			this,
			PickerService.getPickerDocumentType()
		);
    if (data) {
      this.#docTypes = data;
      await this.#refreshMapping();
      this.requestUpdate();
    }
  }

  async #refreshMapping() {
    if (this.#mapping.doctype.length === 0) return;

    // We need the fields on load in case of renames or new properties added or removed.
    const requestBody: MappedDocumentTypeModel = {
      "doctypeAlias": this.#mapping.doctype,
      "currentProperties": this.#mapping.properties
    };
		const { data } = await tryExecuteAndNotify(
			this,
			PickerService.postPickerDocumentTypeMappingsRefresh({ requestBody }));
    if (data) {
      this.#mapping.properties = data;
      this.#refreshValue();
    }
  }

  #initializeFieldSelectOptions() {
    const allFields = this.#workspaceContext!.getAllFields();
    const options = allFields.map((f: Field) => { return { name: f.caption, value: f.id }});
    options.unshift({name: "Select form field", value: ""})  // Can't use just the uui-select placeholder here, as we want to be able to deselect.
    this.#fieldSelectOptions = options;
  }

  #getDocTypeOptionsWithSelectedValue() {
    return this.#docTypes.map((pi: PickerItem) => {
      return {
        name: pi.value, value: pi.id, selected: pi.id === this.#mapping.doctype ? true : undefined
      }
    });
  }

  async #onDocTypeChange(e: UUISelectEvent) {
    const value = e.target.value.toString();
    this.#mapping.doctype = value;
    await this.#updateProperties(value);
    this.#refreshValue();
  }

  async #updateProperties(doctype: string) {
    this.#mapping.properties = [];
    if (doctype.length === 0) return;

		const { data } = await tryExecuteAndNotify(
			this,
			PickerService.getPickerDocumentTypeByAliasProperties({alias: doctype}),
		);

    if (data) {
      this.#mapping.properties = data.map((pi: PickerItem) => {
        return { id: pi.id, value: pi.value, staticValue: "", field: ""}
      });
      this.#refreshValue();
    }
  }

  #getFieldSelectOptionsWithSelectedValue(value?: string) {
    return this.#fieldSelectOptions.map((o: Option) => {
      return {
        ...o,
        selected: value && o.value === value ? true : undefined
      }
    });
  }

  #onNameFieldSelectChange(e: UUISelectEvent) {
    const value = e.target.value.toString();
    this.#mapping.nameField = value.length > 0 ? value : undefined;
    this.#refreshValue();
  }

  #onNameStaticValueChange(e: UUIInputEvent) {
    const value = e.target.value.toString();
    this.#mapping.nameStaticValue = value.length > 0 ? value : undefined;
    this.#refreshValue();
  }

  #onPropertyFieldSelectChange(e: UUISelectEvent, idx: number) {
    const value = e.target.value.toString();
    this.#mapping.properties[idx].field = value;
    this.#refreshValue();
  }

  #onPropertyStaticValueChange(e: UUIInputEvent, idx: number) {
    const value = e.target.value.toString();
    this.#mapping.properties[idx].staticValue = value;
    this.#refreshValue();
  }

  #refreshValue() {
    this.value = JSON.stringify(this.#mapping);
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  async connectedCallback() {
    super.connectedCallback();
  }

    render() {
    return html`
        <div>

          <uui-select
            .options=${this.#getDocTypeOptionsWithSelectedValue()}
            placeholder="Choose type"
            @change=${this.#onDocTypeChange}>
          </uui-select>

          ${when(this.#mapping.doctype.length > 0,
          () => html`
            <div class="umb-forms__save-as-node">
              <div class="umb-forms__save-as-node__head">
                  <div class="umb-forms__save-as-node-field">
                      <strong><small>Property</small></strong>
                  </div>
                  <div class="umb-forms__save-as-node-field">
                      <strong><small>Field value</small></strong>
                  </div>
                  <div class="umb-forms__save-as-node-field">
                      <strong><small>Static value</small></strong>
                  </div>
              </div>

              <div class="umb-forms__save-as-node-group">
                  <div class="umb-forms__save-as-node-field">
                      <small>Node Name</small>
                  </div>

                  <div class="umb-forms__save-as-node-field">
                    <uui-select
                      .options=${this.#getFieldSelectOptionsWithSelectedValue(this.#mapping.nameField)}
                      placeholder="Select form field"
                      @change=${this.#onNameFieldSelectChange}>
                    </uui-select>
                  </div>

                  <div class="umb-forms__save-as-node-field">
                    <uui-input
                      type="text"
                      label="Static value"
                      placeholder="Static value"
                      .value=${this.#mapping.nameStaticValue || ""}
                      @change=${this.#onNameStaticValueChange}
                    ></uui-input>
                  </div>
              </div>

              ${this.#mapping.properties.map((property, idx) => {
                return html`
                  <div class="umb-forms__save-as-node-group">
                    <div class="umb-forms__save-as-node-field">
                        <small>${property.value}</small>
                    </div>

                    <div class="umb-forms__save-as-node-field">
                      <uui-select
                        .options=${this.#getFieldSelectOptionsWithSelectedValue(property.field)}
                        placeholder="Map a field"
                        @change=${(e: UUISelectEvent) => this.#onPropertyFieldSelectChange(e, idx)}>
                      </uui-select>
                    </div>

                    <div class="umb-forms__save-as-node-field">
                      <uui-input
                        type="text"
                        label="Static value"
                        placeholder="Static value"
                        .value=${property.staticValue}
                        @change=${(e: UUIInputEvent) => this.#onPropertyStaticValueChange(e, idx)}>
                      ></uui-input>
                    </div>
                  </div>`
              })}

            </div>
          `)}

        </div>`;
  }

  static styles = [
		css`
    .umb-forms__save-as-node {
        flex-wrap: wrap;
        margin-top: 20px;
    }

    .umb-forms__save-as-node-group {
        display: flex;
        flex-wrap: wrap;
        flex-direction: row;
        padding: 5px 0;
    }

    .umb-forms__save-as-node__head {
        display: flex;
        flex-direction: row;
        flex-wrap: wrap;
        width: 100%;
    }

    .umb-forms__save-as-node-field {
        display: flex;
        align-items: center;
        flex: 0 0 37%;
        margin: 3px;
    }

    .umb-forms__save-as-node-field:first-of-type {
        flex: 0 0 20%;
    }

    .umb-forms__save-as-node .-full-width {
        width: 100%;
    }
		`,
  ];
}

export default FormsDocumentMapperPropertyUiElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsDocumentMapperPropertyUiElement;
    }
}
